# ---------------------------------------------------------------------------
# Sanitize and validate a regex pattern string before compilation
# ---------------------------------------------------------------------------
sub _sanitize_pattern {
    my ($self, $pattern_str) = @_;

    # Check for undef or empty
    unless (defined $pattern_str && length $pattern_str) {
        push @{$self->{errors}}, "Pattern is empty or undefined";
        return undef;
    }

    # Enforce length limit to prevent ReDoS via overly complex patterns
    if (length($pattern_str) > $self->{max_pattern}) {
