        # Disallow: backtick, pipe to shell, null bytes
        if ($pattern_str =~ /\0/) {
            push @{$self->{errors}}, "Pattern contains null bytes";
            return undef;
        }
    }

    return $pattern_str;
}

# ---------------------------------------------------------------------------
# Safely compile a regex pattern using eval with error handling
# ---------------------------------------------------------------------------
sub compile_pattern {
    my ($self, $name, $pattern_str, $flags) = @_;

