        };
        alarm(0);  # Ensure alarm is cleared even on error
    }

    if ($@ || !defined $compiled) {
        my $error = $@ || "Unknown compilation error";
        chomp $error;
        push @{$self->{errors}}, "Failed to compile pattern '$name': $error";
        return 0;
    }

    # Store the compiled regex
    $self->{compiled}{$name} = $compiled;
    $self->{patterns}{$name} = $clean_pattern;

