}

# ---------------------------------------------------------------------------
# Validate an input string against a named compiled pattern
# ---------------------------------------------------------------------------
sub validate {
    my ($self, $name, $input) = @_;

    $self->{errors} = [];

    unless (exists $self->{compiled}{$name}) {
        push @{$self->{errors}}, "No compiled pattern found with name '$name'";
        return undef;
    }

    unless (defined $input) {
        push @{$self->{errors}}, "Input is undefined";
        return 0;
    }

    if (length($input) > $self->{max_input}) {
        push @{$self->{errors}}, "Input exceeds maximum length of $self->{max_input}";
        return 0;
    }

    my $regex = $self->{compiled}{$name};
    my $matched;

    # Use alarm to prevent catastrophic backtracking during matching
    local $SIG{ALRM} = sub { die "Pattern matching timed out (possible ReDoS)\n" };
    eval {
        alarm($self->{timeout});
        $matched = ($input =~ $regex) ? 1 : 0;
        alarm(0);
    };
    alarm(0);

    if ($@) {
        my $error = $@;
        chomp $error;
        push @{$self->{errors}}, "Matching error for pattern '$name': $error";
        return undef;
    }

    return $matched;
}

# ---------------------------------------------------------------------------
# Bulk validate: test input against multiple named patterns
# ---------------------------------------------------------------------------
sub validate_all {
    my ($self, $input, @pattern_names) = @_;

    my %results;
    for my $name (@pattern_names) {
