}

# ---------------------------------------------------------------------------
# Load patterns from a configuration hash
# ---------------------------------------------------------------------------
sub load_config {
    my ($self, $config) = @_;

    unless (ref $config eq 'HASH') {
        push @{$self->{errors}}, "Configuration must be a hash reference";
        return 0;
    }

    my $all_ok = 1;
    for my $name (sort keys %$config) {
        my $entry = $config->{$name};
        my ($pattern, $flags);

        if (ref $entry eq 'HASH') {
            $pattern = $entry->{pattern};
            $flags   = $entry->{flags} // '';
        } else {
            $pattern = $entry;
            $flags   = '';
        }

        unless ($self->compile_pattern($name, $pattern, $flags)) {
            warn "WARNING: Failed to compile pattern '$name': " . join(', ', @{$self->{errors}}) . "\n";
            $all_ok = 0;
        }
    }

    return $all_ok;
}

# ---------------------------------------------------------------------------
# Get error messages
# ---------------------------------------------------------------------------
sub errors {
    my ($self) = @_;
    return @{$self->{errors}};
}

# ---------------------------------------------------------------------------
# List all compiled pattern names
# ---------------------------------------------------------------------------
sub list_patterns {
    my ($self) = @_;
    return sort keys %{$self->{compiled}};
}

# ---------------------------------------------------------------------------
# Remove a compiled pattern
# ---------------------------------------------------------------------------
sub remove_pattern {
    my ($self, $name) = @_;
    delete $self->{compiled}{$name};
    delete $self->{patterns}{$name};
    return 1;
}

